import os
from flask import Flask, request, send_file, jsonify
app = Flask(__name__)


@app.route('/ls', methods=['GET'])
def ls():
    path = request.args['path'] if 'path' in request.args else '/'

    # Get the full path from the relative path provided by user
    fullPath = os.path.normpath(os.path.join(root, path))

    # If the path is not a directory or root then return 403 error
    if not os.path.isdir(fullPath) and fullPath != root:
        return jsonify({'error': 'Forbidden'}), 403

    # Get the list of files in the directory
    fileList = [f for f in os.listdir(fullPath)]

    # Return the list as json response
    return jsonify({
        'files': fileList,
        'path': path
    })


@app.route('/download', methods=['GET'])
def download():
    path = request.args['path'] if 'path' in request.args else '/'

    fullPath = os.path.normpath(os.path.join(root, path))

    # If the path is not a file then return 403 error
    if not os.path.isfile(fullPath):
        return jsonify({'error': 'Forbidden'}), 403

    return send_file(fullPath)


@app.route('/info', methods=['GET'])
def info():
    path = request.args['path'] if 'path' in request.args else '/'

    fullPath = os.path.normpath(os.path.join(root, path))

    # If the path is not a file then return 403 error
    if not os.path.isfile(fullPath):
        return jsonify({'error': 'Forbidden'}), 403

    # Get the file info using os.stat() and return it as json response
    return jsonify({
        'file_info': os.stat(fullPath)
    })


